// Lightweight local gzip helper with an fflate-like surface for this static app.
// It uses the browser Compression Streams API when available and keeps the app fully client-side.
window.fflate={async gunzipAsync(bytes,cb){try{if(!('DecompressionStream' in window))throw new Error('This browser does not provide DecompressionStream. Use an uncompressed .INX file or a browser with gzip stream support.');const stream=new Blob([bytes]).stream().pipeThrough(new DecompressionStream('gzip'));const ab=await new Response(stream).arrayBuffer();cb(null,new Uint8Array(ab));}catch(e){cb(e)}}};
